#include <bits/stdc++.h>
using namespace std;
int n;
bool mp[1300][1300];
void sm(int n,int x,int y) {
	if(n==1) {
		mp[1][1]=1;
		return ;
	}
	int len=pow(2,n);
	for(int i=x;i<=x+len/2-1;i++){
		for(int j=0;j<=y+len/2-1;j++){
			mp[i][j]=1;
		}
	}
	sm(n-1,x,y+len/2);
	sm(n-1,x+len/2,y);
	sm(n-1,x+len/2,y+len/2);
}
void print() {
	for(int i=1; i<=pow(2,n); i++) {
		for(int j=1; j<=pow(2,n); j++) {
			cout<<!mp[i][j]<<" ";
		}
		cout<<"\n";
	}
}
int main() {
	cin>>n;
//	n=pow(2,n);
//	for(int i=1; i<=n; i++) {
//		mp[i][n]=mp[n][i]=1;
//	}
	sm(n,1,1);
	print();
	return 0;
}
